// Liquid Glass shared styles
export const glass = (dark, accent = null) => ({
  background: dark ? 'rgba(255,255,255,0.05)' : 'rgba(255,255,255,0.60)',
  border: `1px solid ${dark ? 'rgba(255,255,255,0.10)' : 'rgba(255,255,255,0.80)'}`,
  backdropFilter: 'blur(24px) saturate(180%)',
  WebkitBackdropFilter: 'blur(24px) saturate(180%)',
  boxShadow: dark
    ? '0 4px 24px rgba(0,0,0,0.3), inset 0 1px 0 rgba(255,255,255,0.06)'
    : '0 4px 24px rgba(26,26,46,0.08), inset 0 1px 0 rgba(255,255,255,0.9)',
});

export const glassHover = (dark, glow) => ({
  boxShadow: `0 20px 60px ${glow}, inset 0 1px 0 ${dark ? 'rgba(255,255,255,0.08)' : 'rgba(255,255,255,0.95)'}`,
  transform: 'translateY(-5px)',
  border: `1px solid ${dark ? 'rgba(255,255,255,0.15)' : 'rgba(255,255,255,0.95)'}`,
});
